public class Transaction implements Serializable {
    public enum TransactionType {
        TRANSFER, DEPOSIT, WITHDRAWAL, PAYMENT
    }

    public enum TransactionStatus {
        PENDING, COMPLETED, FAILED, CANCELLED
    }

    private final String transactionId;
    private final String sourceAccountId;
    private final String destinationAccountId;
    private final BigDecimal amount;
    private final String currency;
    private final TransactionType type;
    private TransactionStatus status;
    private final long timestamp;
    private String description;
    private String failureReason;

    private Transaction(Builder builder) {
        this.transactionId = UUID.randomUUID().toString();
        this.sourceAccountId = builder.sourceAccountId;
        this.destinationAccountId = builder.destinationAccountId;
        this.amount = builder.amount;
        this.currency = builder.currency;
        this.type = builder.type;
        this.status = TransactionStatus.PENDING;
        this.timestamp = System.currentTimeMillis();
        this.description = builder.description;
    }

    public String getTransactionId() { return transactionId; }
    public String getSourceAccountId() { return sourceAccountId; }
    public String getDestinationAccountId() { return destinationAccountId; }
    public BigDecimal getAmount() { return amount; }
    public String getCurrency() { return currency; }
    public TransactionType getType() { return type; }
    public TransactionStatus getStatus() { return status; }
    public void setStatus(TransactionStatus status) { this.status = status; }
    public long getTimestamp() { return timestamp; }
    public String getDescription() { return description; }
    public String getFailureReason() { return failureReason; }
    public void setFailureReason(String reason) { this.failureReason = reason; }

    public static class Builder {
        private String sourceAccountId;
        private String destinationAccountId;
        private BigDecimal amount;
        private String currency = "USD";
        private TransactionType type;
        private String description;

        public Builder sourceAccount(String accountId) {
            this.sourceAccountId = accountId;
            return this;
        }

        public Builder destinationAccount(String accountId) {
            this.destinationAccountId = accountId;
            return this;
        }

        public Builder amount(BigDecimal amount) {
            this.amount = amount;
            return this;
        }

        public Builder currency(String currency) {
            this.currency = currency;
            return this;
        }

        public Builder type(TransactionType type) {
            this.type = type;
            return this;
        }

        public Builder description(String description) {
            this.description = description;
            return this;
        }

        public Transaction build() {
            if (sourceAccountId == null || sourceAccountId.isEmpty()) {
                throw new IllegalArgumentException("Source account is required");
            }
            if (amount == null || amount.compareTo(BigDecimal.ZERO) <= 0) {
                throw new IllegalArgumentException("Amount must be positive");
            }
            if (type == null) {
                throw new IllegalArgumentException("Transaction type is required");
            }
            if (type == TransactionType.TRANSFER && (destinationAccountId == null || destinationAccountId.isEmpty())) {
                throw new IllegalArgumentException("Destination account required for transfers");
            }
            return new Transaction(this);
        }
    }
}

