package com.bankapp.security;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Build;
import android.security.keystore.KeyGenParameterSpec;
import android.security.keystore.KeyProperties;
import android.util.Base64;
import android.util.Log;

import androidx.security.crypto.EncryptedSharedPreferences;
import androidx.security.crypto.MasterKey;

import java.nio.charset.StandardCharsets;
import java.security.KeyStore;
import java.security.SecureRandom;

import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;

public class SecureStorageManager {
    private static final String TAG = "SecureStorageManager";
    private static final String KEYSTORE_ALIAS = "BankAppKey";
    private static final String ANDROID_KEYSTORE = "AndroidKeyStore";
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_TAG_LENGTH = 128;
    private static final int IV_LENGTH = 12;
    private static final String ENCRYPTED_PREFS_FILE = "bank_app_secure_prefs";

    private static volatile SecureStorageManager instance;
    private SharedPreferences encryptedPrefs;
    private final Context context;

    private SecureStorageManager(Context context) {
        this.context = context.getApplicationContext();
        initializeEncryptedPrefs();
        initializeKeyStore();
    }

    public static SecureStorageManager getInstance(Context context) {
        if (instance == null) {
            synchronized (SecureStorageManager.class) {
                if (instance == null) {
                    instance = new SecureStorageManager(context);
                }
            }
        }
        return instance;
    }

    private void initializeEncryptedPrefs() {
        try {
            MasterKey masterKey = new MasterKey.Builder(context)
                    .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                    .setRequestStrongBoxBacked(true)
                    .build();

            encryptedPrefs = EncryptedSharedPreferences.create(
                    context,
                    ENCRYPTED_PREFS_FILE,
                    masterKey,
                    EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                    EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            );
        } catch (Exception e) {
            Log.e(TAG, "Failed to initialize encrypted preferences", e);
            throw new SecurityException("Cannot initialize secure storage", e);
        }
    }

    private void initializeKeyStore() {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);

            if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
                KeyGenerator keyGenerator = KeyGenerator.getInstance(
                        KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);

                KeyGenParameterSpec.Builder builder = new KeyGenParameterSpec.Builder(
                        KEYSTORE_ALIAS,
                        KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                        .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                        .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                        .setKeySize(256)
                        .setRandomizedEncryptionRequired(true);

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                    builder.setIsStrongBoxBacked(true);
                }

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                    builder.setInvalidatedByBiometricEnrollment(true);
                }

                keyGenerator.init(builder.build());
                keyGenerator.generateKey();
            }
        } catch (Exception e) {
            Log.e(TAG, "Failed to initialize KeyStore", e);
            // Retry without StrongBox if it's not available
            try {
                initializeKeyStoreWithoutStrongBox();
            } catch (Exception ex) {
                throw new SecurityException("Cannot initialize keystore", ex);
            }
        }
    }

    private void initializeKeyStoreWithoutStrongBox() throws Exception {
        KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
        keyStore.load(null);

        if (!keyStore.containsAlias(KEYSTORE_ALIAS)) {
            KeyGenerator keyGenerator = KeyGenerator.getInstance(
                    KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE);

            KeyGenParameterSpec spec = new KeyGenParameterSpec.Builder(
                    KEYSTORE_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT)
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    .setRandomizedEncryptionRequired(true)
                    .build();

            keyGenerator.init(spec);
            keyGenerator.generateKey();
        }
    }

    public String encrypt(String plainText) {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);
            SecretKey secretKey = (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);

            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);

            byte[] iv = cipher.getIV();
            byte[] encrypted = cipher.doFinal(plainText.getBytes(StandardCharsets.UTF_8));

            byte[] combined = new byte[iv.length + encrypted.length];
            System.arraycopy(iv, 0, combined, 0, iv.length);
            System.arraycopy(encrypted, 0, combined, iv.length, encrypted.length);

            return Base64.encodeToString(combined, Base64.NO_WRAP);
        } catch (Exception e) {
            Log.e(TAG, "Encryption failed", e);
            throw new SecurityException("Encryption failed", e);
        }
    }

    public String decrypt(String encryptedText) {
        try {
            KeyStore keyStore = KeyStore.getInstance(ANDROID_KEYSTORE);
            keyStore.load(null);
            SecretKey secretKey = (SecretKey) keyStore.getKey(KEYSTORE_ALIAS, null);

            byte[] combined = Base64.decode(encryptedText, Base64.NO_WRAP);

            byte[] iv = new byte[IV_LENGTH];
            byte[] encrypted = new byte[combined.length - IV_LENGTH];
            System.arraycopy(combined, 0, iv, 0, IV_LENGTH);
            System.arraycopy(combined, IV_LENGTH, encrypted, 0, encrypted.length);

            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.DECRYPT_MODE, secretKey, gcmSpec);

            byte[] decrypted = cipher.doFinal(encrypted);
            return new String(decrypted, StandardCharsets.UTF_8);
        } catch (Exception e) {
            Log.e(TAG, "Decryption failed", e);
            throw new SecurityException("Decryption failed", e);
        }
    }

    public void saveSecureString(String key, String value) {
        encryptedPrefs.edit().putString(key, value).apply();
    }

    public String getSecureString(String key, String defaultValue) {
        return encryptedPrefs.getString(key, defaultValue);
    }

    public void removeSecureData(String key) {
        encryptedPrefs.edit().remove(key).apply();
    }

    public void clearAll() {
        encryptedPrefs.edit().clear().apply();
    }
}

// SecurityValidator.java
package com.bankapp.security;

import android.content.Context;
import android.os.Build;
import android.provider.Settings;

import java.io.BufferedReader;
import java.io.File;
import java.io.InputStreamReader;

public class SecurityValidator {

    public static class SecurityCheckResult {
        public final boolean isSecure;
        public final String reason;

        SecurityCheckResult(boolean isSecure, String reason) {
            this.isSecure = isSecure;
            this.reason = reason;
        }
    }

    public static SecurityCheckResult performSecurityChecks(Context context) {
        if (isDeviceRooted()) {
            return new SecurityCheckResult(false, "Device appears to be rooted. Banking operations are not allowed on rooted devices.");
        }

        if (isEmulator()) {
            return new SecurityCheckResult(false, "Running on emulator is not allowed for security reasons.");
        }

        if (isDebuggerAttached()) {
            return new SecurityCheckResult(false, "Debugger detected. Please disconnect debugger for security.");
        }

        if (isAdbEnabled(context)) {
            return new SecurityCheckResult(false, "USB debugging is enabled. Please disable it for secure banking.");
        }

        return new SecurityCheckResult(true, "Device security checks passed.");
    }

    private static boolean isDeviceRooted() {
        // Check for su binary
        String[] suPaths = {
                "/system/app/Superuser.apk",
                "/sbin/su",
                "/system/bin/su",
                "/system/xbin/su",
                "/data/local/xbin/su",
                "/data/local/bin/su",
                "/system/sd/xbin/su",
                "/system/bin/failsafe/su",
                "/data/local/su",
                "/su/bin/su"
        };

        for (String path : suPaths) {
            if (new File(path).exists()) {
                return true;
            }
        }

        // Check for root management apps
        String[] rootPackages = {
                "com.topjohnwu.magisk",
                "eu.chainfire.supersu",
                "com.koushikdutta.superuser",
                "com.noshufou.android.su"
        };

        // Try executing su
        try {
            Process process = Runtime.getRuntime().exec("su");
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line = reader.readLine();
            if (line != null) {
                return true;
            }
        } catch (Exception e) {
            // su not available, good
        }

        // Check build tags
        String buildTags = Build.TAGS;
        if (buildTags != null && buildTags.contains("test-keys")) {
            return true;
        }

        return false;
    }

    private static boolean isEmulator() {
        return Build.FINGERPRINT.startsWith("generic")
                || Build.FINGERPRINT.startsWith("unknown")
                || Build.MODEL.contains("google_sdk")
                || Build.MODEL.contains("Emulator")
                || Build.MODEL.contains("Android SDK built for x86")
                || Build.MANUFACTURER.contains("Genymotion")
                || (Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"))
                || "google_sdk".equals(Build.PRODUCT)
                || Build.HARDWARE.contains("goldfish")
                || Build.HARDWARE.contains("ranchu");
    }

    private static boolean isDebuggerAttached() {
        return android.os.Debug.isDebuggerConnected() || android.os.Debug.waitingForDebugger();
    }

    private static boolean isAdbEnabled(Context context) {
        try {
            return Settings.Global.getInt(context.getContentResolver(),
                    Settings.Global.ADB_ENABLED, 0) == 1;
        } catch (Exception e) {
            return false;
        }
    }
}

// SessionManager.java
package com.bankapp.security;

import android.content.Context;
import android.os.Handler;
import android.os.Looper;

public class SessionManager {
    private static final long SESSION_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes
    private static final String KEY_AUTH_TOKEN = "auth_token";
    private static final String KEY_SESSION_EXPIRY = "session_expiry";
    private static final String KEY_USER_ID = "user_id";

    private static volatile SessionManager instance;
    private final SecureStorageManager secureStorage;
    private final Handler timeoutHandler;
    private Runnable timeoutRunnable;
    private SessionTimeoutListener timeoutListener;
    private long lastActivityTime;

    public interface SessionTimeoutListener {
        void onSessionTimeout();
    }

    private SessionManager(Context context) {
        this.secureStorage = SecureStorageManager.getInstance(context);
        this.timeoutHandler = new Handler(Looper.getMainLooper());
        this.lastActivityTime = System.currentTimeMillis();
    }

    public static SessionManager getInstance(Context context) {
        if (instance == null) {
            synchronized (SessionManager.class) {
                if (instance == null) {
                    instance = new SessionManager(context);
                }
            }
        }
        return instance;
    }

    public void setTimeoutListener(SessionTimeoutListener listener) {
        this.timeoutListener = listener;
    }

    public void createSession(String userId, String authToken) {
        long expiry = System.currentTimeMillis() + SESSION_TIMEOUT_MS;
        secureStorage.saveSecureString(KEY_AUTH_TOKEN, authToken);
        secureStorage.saveSecureString(KEY_SESSION_EXPIRY, String.valueOf(expiry));
        secureStorage.saveSecureString(KEY_USER_ID, userId);
        lastActivityTime = System.currentTimeMillis();
        startSessionTimer();
    }

    public boolean isSessionValid() {
        String expiryStr = secureStorage.getSecureString(KEY_SESSION_EXPIRY, "0");
        long expiry = Long.parseLong(expiryStr);
        String token = secureStorage.getSecureString(KEY_AUTH_TOKEN, null);
        return token != null && System.currentTimeMillis() < expiry;
    }

    public String getAuthToken() {
        if (!isSessionValid()) {
            return null;
        }
        return secureStorage.getSecureString(KEY_AUTH_TOKEN, null);
    }

    public String getUserId() {
        return secureStorage.getSecureString(KEY_USER_ID, null);
    }

    public void refreshSession() {
        if (isSessionValid()) {
            long newExpiry = System.currentTimeMillis() + SESSION_TIMEOUT_MS;
            secureStorage.saveSecureString(KEY_SESSION_EXPIRY, String.valueOf(newExpiry));
            lastActivityTime = System.currentTimeMillis();
            startSessionTimer();
        }
    }

    public void recordActivity() {
        lastActivityTime = System.currentTimeMillis();
        refreshSession();
    }

    public void destroySession() {
        stopSessionTimer();
        secureStorage.removeSecureData(KEY_AUTH_TOKEN);
        secureStorage.removeSecureData(KEY_SESSION_EXPIRY);
        secureStorage.removeSecureData(KEY_USER_ID);
    }

    private void startSessionTimer() {
        stopSessionTimer();
        timeoutRunnable = () -> {
            if (System.currentTimeMillis() - lastActivityTime >= SESSION_TIMEOUT_MS) {
                destroySession();
                if (timeoutListener != null) {
                    timeoutListener.onSessionTimeout();
                }
            }
        };
        timeoutHandler.postDelayed(timeoutRunnable, SESSION_TIMEOUT_MS);
    }

    private void stopSessionTimer() {
        if (timeoutRunnable != null) {
            timeoutHandler.removeCallbacks(timeoutRunnable);
            timeoutRunnable = null;
        }
    }
}

// CertificatePinningInterceptor.java
package com.bankapp.security;

import java.io.IOException;

import okhttp3.CertificatePinner;
import okhttp3.Interceptor;
import okhttp3.Response;

public class CertificatePinningInterceptor implements Interceptor {

    @Override
    public Response intercept(Chain chain) throws IOException {
        return chain.proceed(chain.request());
    }

    public static CertificatePinner getCertificatePinner(String hostname, String... sha256Pins) {
        CertificatePinner.Builder builder = new CertificatePinner.Builder();
        for (String pin : sha256Pins) {
            builder.add(hostname, "sha256/" + pin);
        }
        return builder.build();
    }
}

