package com.bankapp.network;

import android.content.Context;

import com.bankapp.security.CertificatePinningInterceptor;
import com.bankapp.security.SessionManager;

import java.io.IOException;
import java.util.concurrent.TimeUnit;

import okhttp3.CertificatePinner;
import okhttp3.Interceptor;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.Response;

public class ApiClient {
    private static final String BASE_URL = "https://api.securebank.example.com/v1/";
    private static final String API_HOST = "api.securebank.example.com";
    // Replace with actual certificate pin hashes
    private static final String PIN_1 = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=";
    private static final String PIN_2 = "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=";

    private static volatile ApiClient instance;
    private final OkHttpClient httpClient;
    private final Context context;

    private ApiClient(Context context) {
        this.context = context.getApplicationContext();

        CertificatePinner certificatePinner = CertificatePinningInterceptor
                .getCertificatePinner(API_HOST, PIN_1, PIN_2);

        httpClient = new OkHttpClient.Builder()
                .connectTimeout(30, TimeUnit.SECONDS)
                .readTimeout(30, TimeUnit.SECONDS)
                .writeTimeout(30, TimeUnit.SECONDS)
                .certificatePinner(certificatePinner)
                .addInterceptor(new AuthInterceptor())
                .addInterceptor(new CertificatePinningInterceptor())
                .build();
    }

    public static ApiClient getInstance(Context context) {
        if (instance == null) {
            synchronized (ApiClient.class) {
                if (instance == null) {
                    instance = new ApiClient(context);
                }
            }
        }
        return instance;
    }

    public OkHttpClient getHttpClient() {
        return httpClient;
    }

    public String getBaseUrl() {
        return BASE_URL;
    }

    private class AuthInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request originalRequest = chain.request();
            SessionManager sessionManager = SessionManager.getInstance(context);
            String token = sessionManager.getAuthToken();

            if (token != null) {
                Request authenticatedRequest = originalRequest.newBuilder()
                        .header("Authorization", "Bearer " + token)
                        .header("Content-Type", "application/json")
                        .header("X-Request-ID", java.util.UUID.randomUUID().toString())
                        .build();
                return chain.proceed(authenticatedRequest);
            }

            return chain.proceed(originalRequest);
        }
    }
}

