// TransactionValidator.java
package com.bankapp.transaction;

import com.bankapp.model.Account;
import com.bankapp.model.Transaction;

import java.math.BigDecimal;

public class TransactionValidator {

    private static final BigDecimal MAX_SINGLE_TRANSACTION = new BigDecimal("50000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");
    private static final BigDecimal DAILY_TRANSFER_LIMIT = new BigDecimal("100000.00");

    public static class ValidationResult {
        public final boolean isValid;
        public final String errorMessage;
        public final String errorCode;

        ValidationResult(boolean isValid, String errorMessage, String errorCode) {
            this.isValid = isValid;
            this.errorMessage = errorMessage;
            this.errorCode = errorCode;
        }

        public static ValidationResult valid() {
            return new ValidationResult(true, null, null);
        }

        public static ValidationResult invalid(String message, String code) {
            return new ValidationResult(false, message, code);
        }
    }

    public static ValidationResult validate(Transaction transaction, Account sourceAccount) {
        // Check amount is positive and within bounds
        if (transaction.getAmount() == null) {
            return ValidationResult.invalid("Transaction amount is required", "INVALID_AMOUNT");
        }

        if (transaction.getAmount().compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
            return ValidationResult.invalid(
                    "Minimum transaction amount is " + MIN_TRANSACTION_AMOUNT.toPlainString(),
                    "AMOUNT_TOO_LOW");
        }

        if (transaction.getAmount().compareTo(MAX_SINGLE_TRANSACTION) > 0) {
            return ValidationResult.invalid(
                    "Maximum single transaction is " + MAX_SINGLE_TRANSACTION.toPlainString(),
                    "AMOUNT_TOO_HIGH");
        }

        // Check sufficient balance
        if (sourceAccount != null) {
            if (!sourceAccount.isActive()) {
                return ValidationResult.invalid("Source account is inactive", "ACCOUNT_INACTIVE");
            }

            if (transaction.getType() == Transaction.TransactionType.TRANSFER
                    || transaction.getType() == Transaction.TransactionType.WITHDRAWAL
                    || transaction.getType() == Transaction.TransactionType.PAYMENT) {

                if (sourceAccount.getAvailableBalance().compareTo(transaction.getAmount()) < 0) {
                    return ValidationResult.invalid("Insufficient funds", "INSUFFICIENT_FUNDS");
                }
            }
        }

        // Check currency match
        if (sourceAccount != null && !sourceAccount.getCurrency().equals(transaction.getCurrency())) {
            return ValidationResult.invalid("Currency mismatch", "CURRENCY_MISMATCH");
        }

        // Validate transfer-specific requirements
        if (transaction.getType() == Transaction.TransactionType.TRANSFER) {
            if (transaction.getDestinationAccountId() == null
                    || transaction.getDestinationAccountId().isEmpty()) {
                return ValidationResult.invalid("Destination account is required for transfers",
                        "MISSING_DESTINATION");
            }

            if (transaction.getSourceAccountId().equals(transaction.getDestinationAccountId())) {
                return ValidationResult.invalid("Cannot transfer to the same account",
                        "SAME_ACCOUNT_TRANSFER");
            }
        }

        return ValidationResult.valid();
    }

    public static ValidationResult validateDailyLimit(BigDecimal todaysTotalTransactions,
                                                        BigDecimal newTransactionAmount) {
        BigDecimal newTotal = todaysTotalTransactions.add(newTransactionAmount);
        if (newTotal.compareTo(DAILY_TRANSFER_LIMIT) > 0) {
            BigDecimal remaining = DAILY_TRANSFER_LIMIT.subtract(todaysTotalTransactions);
            return ValidationResult.invalid(
                    "Daily transfer limit exceeded. Remaining limit: " + remaining.toPlainString(),
                    "DAILY_LIMIT_EXCEEDED");
        }
        return ValidationResult.valid();
    }
}

// TransactionProcessor.java
package com.bankapp.transaction;

import android.content.Context;
import android.util.Log;

import com.bankapp.model.Account;
import com.bankapp.model.Transaction;
import com.bankapp.model.TransactionResult;
import com.bankapp.network.BankingApiService;
import com.bankapp.security.SecureStorageManager;
import com.bankapp.security.SessionManager;

import java.math.BigDecimal;
import java.util.Collections;
import java.util.LinkedList;
import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.atomic.AtomicBoolean;

public class TransactionProcessor {
    private static final String TAG = "TransactionProcessor";
    private static final int MAX_RETRY_COUNT = 3;
    private static final long RETRY_DELAY_MS = 2000;

    private final Context context;
    private final BankingApiService apiService;
    private final SessionManager sessionManager;
    private final SecureStorageManager secureStorage;
    private final ExecutorService executorService;
    private final List<Transaction> pendingTransactions;
    private final AtomicBoolean isProcessing;

    public interface TransactionCallback {
        void onTransactionSuccess(TransactionResult result);
        void onTransactionFailed(TransactionResult result);
        void onValidationFailed(String message, String errorCode);
        void onSessionExpired();
    }

    public TransactionProcessor(Context context) {
        this.context = context.getApplicationContext();
        this.apiService = new BankingApiService(context);
        this.sessionManager = SessionManager.getInstance(context);
        this.secureStorage = SecureStorageManager.getInstance(context);
        this.executorService = Executors.newSingleThreadExecutor();
        this.pendingTransactions = Collections.synchronizedList(new LinkedList<>());
        this.isProcessing = new AtomicBoolean(false);
    }

    public void processTransfer(String sourceAccountId, String destinationAccountId,
                                 BigDecimal amount, String currency, String description,
                                 Account sourceAccount, TransactionCallback callback) {
        // Validate session first
        if (!sessionManager.isSessionValid()) {
            callback.onSessionExpired();
            return;
        }

        sessionManager.recordActivity();

        try {
            Transaction transaction = new Transaction.Builder()
                    .sourceAccount(sourceAccountId)
                    .destinationAccount(destinationAccountId)
                    .amount(amount)
                    .currency(currency)
                    .type(Transaction.TransactionType.TRANSFER)
                    .description(description)
                    .build();

            // Validate transaction
            TransactionValidator.ValidationResult validationResult =
                    TransactionValidator.validate(transaction, sourceAccount);

            if (!validationResult.isValid) {
                callback.onValidationFailed(validationResult.errorMessage, validationResult.errorCode);
                return;
            }

            // Submit transaction
            submitTransaction(transaction, callback, 0);

        } catch (IllegalArgumentException e) {
            callback.onValidationFailed(e.getMessage(), "VALIDATION_ERROR");
        }
    }

    public void processPayment(String sourceAccountId, BigDecimal amount, String currency,
                                String payeeDescription, Account sourceAccount,
                                TransactionCallback callback) {
        if (!sessionManager.isSessionValid()) {
            callback.onSessionExpired();
            return;
        }

        sessionManager.recordActivity();

        try {
            Transaction transaction = new Transaction.Builder()
                    .sourceAccount(sourceAccountId)
                    .amount(amount)
                    .currency(currency)
                    .type(Transaction.TransactionType.PAYMENT)
                    .description(payeeDescription)
                    .build();

            TransactionValidator.ValidationResult validationResult =
                    TransactionValidator.validate(transaction, sourceAccount);

            if (!validationResult.isValid) {
                callback.onValidationFailed(validationResult.errorMessage, validationResult.errorCode);
                return;
            }

            submitTransaction(transaction, callback, 0);

        } catch (IllegalArgumentException e) {
            callback.onValidationFailed(e.getMessage(), "VALIDATION_ERROR");
        }
    }

    public void processWithdrawal(String sourceAccountId, BigDecimal amount, String currency,
                                   Account sourceAccount, TransactionCallback callback) {
        if (!sessionManager.isSessionValid()) {
            callback.onSessionExpired();
            return;
        }

        sessionManager.recordActivity();

        try {
            Transaction transaction = new Transaction.Builder()
                    .sourceAccount(sourceAccountId)
                    .amount(amount)
                    .currency(currency)
                    .type(Transaction.TransactionType.WITHDRAWAL)
                    .description("ATM Withdrawal")
                    .build();

            TransactionValidator.ValidationResult validationResult =
                    TransactionValidator.validate(transaction, sourceAccount);

            if (!validationResult.isValid) {
                callback.onValidationFailed(validationResult.errorMessage, validationResult.errorCode);
                return;
            }

            submitTransaction(transaction, callback, 0);

        } catch (IllegalArgumentException e) {
            callback.onValidationFailed(e.getMessage(), "VALIDATION_ERROR");
        }
    }

    private void submitTransaction(Transaction transaction, TransactionCallback callback,
                                    int retryCount) {
        isProcessing.set(true);
        pendingTransactions.add(transaction);

        Log.i(TAG, "Submitting transaction: " + transaction.getTransactionId()
                + " (attempt " + (retryCount + 1) + ")");

        apiService.processTransaction(transaction, new BankingApiService.ApiCallback<TransactionResult>() {
            @Override
            public void onSuccess(TransactionResult result) {
                isProcessing.set(false);
                pendingTransactions.remove(transaction);

                if (result.isSuccess()) {
                    Log.i(TAG, "Transaction successful: " + transaction.getTransactionId());
                    logTransaction(transaction, true);
                    callback.onTransactionSuccess(result);
                } else {
                    Log.w(TAG, "Transaction failed: " + result.getMessage());
                    logTransaction(transaction, false);
                    callback.onTransactionFailed(result);
                }
            }

            @Override
            public void onError(String errorMessage, String errorCode) {
                isProcessing.set(false);
                pendingTransactions.remove(transaction);

                // Handle session expiry from server
                if ("401".equals(errorCode)) {
                    sessionManager.destroySession();
                    callback.onSessionExpired();
                    return;
                }

                // Retry on network errors
                if ("NETWORK_ERROR".equals(errorCode) && retryCount < MAX_RETRY_COUNT) {
                    Log.w(TAG, "Retrying transaction due to network error, attempt " + (retryCount + 2));
                    executorService.submit(() -> {
                        try {
                            Thread.sleep(RETRY_DELAY_MS * (retryCount + 1)); // Exponential backoff
                        } catch (InterruptedException e) {
                            Thread.currentThread().interrupt();
                        }
                        submitTransaction(transaction, callback, retryCount + 1);
                    });
                    return;
                }

                transaction.setStatus(Transaction.TransactionStatus.FAILED);
                transaction.setFailureReason(errorMessage);
                logTransaction(transaction, false);

                TransactionResult failureResult = TransactionResult.failure(
                        transaction, errorMessage, errorCode);
                callback.onTransactionFailed(failureResult);
            }
        });
    }

    private void logTransaction(Transaction transaction, boolean success) {
        // Audit log - log minimal info, no sensitive data
        Log.i(TAG, String.format("AUDIT: txn=%s type=%s status=%s amount_currency=%s",
                transaction.getTransactionId(),
                transaction.getType(),
                success ? "SUCCESS" : "FAILED",
                transaction.getCurrency()));
    }

    public boolean hasActiveTransactions() {
        return isProcessing.get() || !pendingTransactions.isEmpty();
    }

    public void shutdown() {
        executorService.shutdown();
    }
}

